
CREATE TABLE tariffs (
    id SERIAL PRIMARY KEY,
    pos VARCHAR(4) NOT NULL,
    slug VARCHAR(50) NOT NULL UNIQUE,
    title VARCHAR(200) NOT NULL,
    duration VARCHAR(50) NOT NULL,
    audience TEXT NOT NULL,
    format VARCHAR(300) NOT NULL,
    price INTEGER NOT NULL DEFAULT 0,
    price_label VARCHAR(100),
    includes TEXT[] NOT NULL DEFAULT '{}',
    between_sessions TEXT,
    review_policy TEXT,
    limits_info TEXT,
    cta_text VARCHAR(200) NOT NULL DEFAULT 'Записаться',
    cta_link VARCHAR(200) NOT NULL DEFAULT '/contacts',
    is_popular BOOLEAN NOT NULL DEFAULT FALSE,
    is_warning BOOLEAN NOT NULL DEFAULT FALSE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    sort_order INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

INSERT INTO tariffs (pos, slug, title, duration, audience, format, price, includes, between_sessions, review_policy, limits_info, cta_text, cta_link, is_popular, is_warning, sort_order)
